export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type Result = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: Result[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_PRICE = 25;
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;
const COMPONENT_TYPES = new Set(["rune"]);

const FIRST_INSURANCE_SURCHARGE = 1.1;
const PROCESSING_FEE = 5;
const FLOAT_PRECISION_DIGITS = 6;

const componentBase = (count: number): number => {
  return count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_PRICE;
};

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const itemBaseTotal = (items: Item[]): number => {
  let total = 0;
  for (const [type, count] of countByType(items)) {
    total += COMPONENT_TYPES.has(type)
      ? componentBase(count)
      : BASE_PREMIUM[type] * count;
  }
  return total;
};

const quotePremium = (step: QuoteStep): number => {
  const itemTotal = itemBaseTotal(step.items) * FIRST_INSURANCE_SURCHARGE;
  const premium = itemTotal + PROCESSING_FEE;
  return Math.ceil(Number(premium.toFixed(FLOAT_PRECISION_DIGITS)));
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  return {
    results: scenario.steps.map((step) => ({
      premium: quotePremium(step as QuoteStep),
    })),
  };
};

