import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Base premiums for single main items (incl. first-insurance +10% and 5 G fee) ---
  // For a newcomer (0 years, first quote): premium = base * 1.10 + 5
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });
  it("single sword (base 100) → premium 100*1.10 + 5 = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("single amulet (base 60) → premium 60*1.10 + 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("single staff (base 80) → premium 80*1.10 + 5 = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("single potion (base 40) → premium 40*1.10 + 5 = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 49 });
  });

  // --- Components and building blocks (base premium focus) ---
  it("1 rune (base 25) → premium 25*1.10 + 5 = 32.5 → rounded up 33 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 33 });
  });
  it("2 runes → base 50 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("3 runes → base 60 G (block applies)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("4 runes → base 100 G (no block — block requires exactly 3)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("7 runes → base 175 G (no block — block requires exactly 3; 7*25)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 198 });
  });
  it("2 runes + 1 moonstone → base 75 G (no block: different types)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 88 });
  });
  it("3 runes + 3 moonstones → base 120 G (two separate blocks)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 137 });
  });

  // --- Item-specific premium modifiers ---
  it("cursed sword adds 50% of its base premium (curse surcharge)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    // 100 base + 50 curse + 10 first-insurance (10% of base) + 5 fee = 165
    expect(result.results[0]).toEqual({ premium: 165 });
  });
  it("sword with enchantment exactly 5 → high-enchantment +30% surcharge", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    // 100 base + 30 high-ench + 10 first-insurance + 5 fee = 145
    expect(result.results[0]).toEqual({ premium: 145 });
  });
  it("sword with enchantment 4 → no high-enchantment surcharge", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", enchantment: 5, cursed: true }],
        },
      ],
    });
    // 100 base + 50 curse + 30 high-ench + 10 first + 5 fee = 195
    expect(result.results[0]).toEqual({ premium: 195 });
  });

  // --- Policy-wide modifiers ---
  it("customer with exactly 2 years → 20% loyalty discount on policy base", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    // 100 base + 10 first - 20 loyalty + 5 fee = 95
    expect(result.results[0]).toEqual({ premium: 95 });
  });
  it("customer with 1 year → no loyalty discount", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 1 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("second quote in scenario → 15% follow-up contract discount on policy base", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword" }] },
        { op: "quote", items: [{ type: "sword" }] },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
    // follow-up: 100 + 10 first - 15 follow-up + 5 fee = 100
    expect(result.results[1]).toEqual({ premium: 100 });
  });
  it.todo("first insurance +10% surcharge applies to each item even on a follow-up contract");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword + plain amulet → curse surcharge is 50% of cursed sword base only (210 before fee/modifiers)");

  // --- Rounding ---
  it.todo("premium yielding 197.5 G → rounded up to 198 G");

  // --- Integration examples ---
  it.todo("newcomer cursed sword (0y, ench 3) → premium 165 G");
  it.todo("long-standing 2nd contract (3y, cursed sword ench 7) → premium 160 G");

  // --- Claim processing: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 G (full minus 100 deductible)");
  it.todo("rune damage 200 (value 250) → payout 100 G (full minus 100 deductible, no special clause)");
  it.todo("claim reports remainingCap after a payout");

  // --- Claim processing: special clauses ---
  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 G (full reimbursement then deductible)");
  it.todo("steel sword, ench 9, damage 1000 → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 G (50% wins over dragon, then deductible)");
  it.todo("dragon-material sword, ench exactly 8, damage 1000 → payout 400 G (high-ench clause then deductible)");

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per item)");

  // --- Multiple items of the same type ---
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two sword damages on a two-sword policy → each treated as separate damage with own deductible");
  it.todo("more damage entries of a type than insured items → claim rejected (throws)");

  // --- Cap exhaustion ---
  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount does not affect sum)");
  it.todo("two successive 1500 claims on a 1000-sword policy → payouts 1400 then 600, remaining cap 600 then 0");

  // --- Error / edge cases ---
  it.todo("quote with unknown item type → throws (CLI non-zero exit)");
  it.todo("claim references item not in policy → throws");
  it.todo("claim with negative damage amount → throws");
});

